const listRunWaits = `-- name: ListRunWaits :many
WITH cursor_wait AS (
    SELECT parked_at, id
      FROM run_waits
     WHERE org_id = $1
       AND run_id = $2
       AND id = $4::uuid
)
SELECT id, org_id, project_id, environment_id, run_id, kind, correlation_id, state, timeout_at, runtime_checkpoint_id, workspace_version_id, active_elapsed_ms_at_park, parked_at, resolved_at, resumed_at, cancelled_at, created_at, updated_at
  FROM run_waits
 WHERE run_waits.org_id = $1
   AND run_waits.run_id = $2
   AND (
       $3::text IS NULL
       OR run_waits.state = $3::run_wait_state
   )
   AND (
       $4::uuid IS NULL
       OR (run_waits.parked_at, run_waits.id) > (SELECT cursor_wait.parked_at, cursor_wait.id FROM cursor_wait)
   )
 ORDER BY run_waits.parked_at ASC, run_waits.id ASC
 LIMIT $5
`

type ListRunWaitsParams struct {
	OrgID      pgtype.UUID `json:"org_id"`
	RunID      pgtype.UUID `json:"run_id"`
	State      pgtype.Text `json:"state"`
	AfterID    pgtype.UUID `json:"after_id"`
	LimitCount int32       `json:"limit_count"`
}

func (q *Queries) ListRunWaits(ctx context.Context, arg ListRunWaitsParams) ([]RunWait, error) {
	rows, err := q.db.Query(ctx, listRunWaits,
		arg.OrgID,
		arg.RunID,
		arg.State,
		arg.AfterID,
		arg.LimitCount,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []RunWait
	for rows.Next() {
		var i RunWait
		if err := rows.Scan(
			&i.ID,
			&i.OrgID,
			&i.ProjectID,
			&i.EnvironmentID,
			&i.RunID,
			&i.Kind,
			&i.CorrelationID,
			&i.State,
			&i.TimeoutAt,
			&i.RuntimeCheckpointID,
			&i.WorkspaceVersionID,
			&i.ActiveElapsedMsAtPark,
			&i.ParkedAt,
			&i.ResolvedAt,
			&i.ResumedAt,
			&i.CancelledAt,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

